// Parse Claude response and clean JSON
const raw = $input.item.json.content[0].text;
const cleaned = raw.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();
let memo;
try {
  memo = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Failed to parse memo JSON: ' + e.message + '\nRaw: ' + raw.slice(0,300));
}

// Ensure account_id
if (!memo.account_id && memo.company_name) {
  memo.account_id = memo.company_name.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/-+$/,'') + '-001';
}

return { json: { memo, account_id: memo.account_id } };

