// Save v1 memo and spec as JSON files in outputs/accounts/<id>/v1/
const { memo, spec, account_id } = $input.item.json;
const fs = require('fs');
const path = require('path');

const outDir = path.join(process.env.OUTPUTS_DIR || './outputs/accounts', account_id, 'v1');
fs.mkdirSync(outDir, { recursive: true });

fs.writeFileSync(path.join(outDir, 'account_memo.json'), JSON.stringify(memo, null, 2));
