console.log('[SAVED v1]', outDir);
return { json: { account_id, status: 'v1_saved', memo_path: outDir + '/account_memo.json', spec_path: outDir + '/agent_spec.json' } };

// Load existing v1 memo from disk for Pipeline B
const fs = require('fs');
const path = require('path');
const { account_id } = $input.item.json;
const v1Path = path.join(process.env.OUTPUTS_DIR || './outputs/accounts', account_id, 'v1', 'account_memo.json');

if (!fs.existsSync(v1Path)) {
  throw new Error('No v1 memo found for ' + account_id + '. Run Pipeline A first.');
}

const v1_memo_raw = fs.readFileSync(v1Path, 'utf8');
return { json: { ...($input.item.json), v1_memo_raw, v1_memo: JSON.parse(v1_memo_raw) } };

const raw = $input.item.json.content[0].text;
const cleaned = raw.replace(/^```(?:json)?\s*/m,'').replace(/\s*```$/m,'').trim();
let v2_memo;
try { v2_memo = JSON.parse(cleaned); } catch(e) { throw new Error('v2 memo parse failed: ' + e.message); }
v2_memo.version    = 'v2';
v2_memo.account_id = $('Load v1 Memo').item.json.account_id;

// Diff function
function diffDicts(o, n, p) {
  const changes = [];
  const keys = new Set([...Object.keys(o||{}), ...Object.keys(n||{})]);
  for (const k of keys) {
    const fk = p ? p+'.'+k : k;
    if (!(k in o)) changes.push({field:fk,type:'ADDED',old:null,new:n[k]});
    else if (!(k in n)) changes.push({field:fk,type:'REMOVED',old:o[k],new:null});
    else if (typeof o[k]==='object'&&o[k]&&typeof n[k]==='object'&&n[k]&&!Array.isArray(o[k])) {
      changes.push(...diffDicts(o[k],n[k],fk));
    } else if (JSON.stringify(o[k])!==JSON.stringify(n[k])) {
      changes.push({field:fk,type:'UPDATED',old:o[k],new:n[k]});
    }
  }
  return changes;
}

const v1_memo = $('Load v1 Memo').item.json.v1_memo;
const changes  = diffDicts(v1_memo, v2_memo, '');
const resolved = (v1_memo.questions_or_unknowns||[]).filter(q=>!(v2_memo.questions_or_unknowns||[]).includes(q));

return { json: { v2_memo, account_id: v2_memo.account_id, changes, resolved } };

