const raw = $input.item.json.content[0].text;
const cleaned = raw.replace(/^```(?:json)?\s*/m,'').replace(/\s*```$/m,'').trim();
let v2_spec;
try { v2_spec = JSON.parse(cleaned); } catch(e) { throw new Error('v2 spec parse failed: '+e.message); }
v2_spec.version    = 'v2';
v2_spec.account_id = $('Parse Memo v2 + Diff').item.json.account_id;

const { v2_memo, changes, resolved } = $('Parse Memo v2 + Diff').item.json;
const today = $('Normalize Input').item.json.today;

// Build markdown changelog
let md = `# Changelog\n\n**Date:** ${today}  \n**Transition:** v1 → v2  \n**Changes:** ${changes.length}  \n**Resolved:** ${resolved.length}\n\n## Field Changes\n\n`;
for (const c of changes) {
  md += `### \`${c.field}\` — ${c.type}\n`;
  if (c.type==='UPDATED') md += `- Before: \`${JSON.stringify(c.old)}\`\n- After: \`${JSON.stringify(c.new)}\`\n\n`;
  else if (c.type==='ADDED')   md += `- Added: \`${JSON.stringify(c.new)}\`\n\n`;
  else if (c.type==='REMOVED') md += `- Removed: \`${JSON.stringify(c.old)}\`\n\n`;
}
if (resolved.length) {
  md += `## Resolved Unknowns\n\n`;
  for (const r of resolved) md += `- ✅ ${r}\n`;
}
const still_open = v2_memo.questions_or_unknowns || [];
if (still_open.length) {
  md += `\n## Still Open\n\n`;
  for (const r of still_open) md += `- ❓ ${r}\n`;
}

return { json: { v2_spec, v2_memo, account_id: v2_spec.account_id, changes, resolved, changelog_md: md } };

const fs = require('fs');
const path = require('path');
const { v2_memo, v2_spec, account_id, changes, resolved, changelog_md } = $input.item.json;

const base = process.env.OUTPUTS_DIR || './outputs/accounts';
const v2Dir = path.join(base, account_id, 'v2');
fs.mkdirSync(v2Dir, { recursive: true });

fs.writeFileSync(path.join(v2Dir, 'account_memo.json'), JSON.stringify(v2_memo, null, 2));
fs.writeFileSync(path.join(v2Dir, 'agent_spec.json'),   JSON.stringify(v2_spec, null, 2));
fs.writeFileSync(path.join(base, account_id, 'changelog.md'), changelog_md);
fs.writeFileSync(path.join(base, account_id, 'changelog.json'), JSON.stringify({ account_id, changes, resolved, still_open: v2_memo.questions_or_unknowns||[] }, null, 2));

console.log('[SAVED v2]', v2Dir);
return { json: { account_id, status: 'v2_saved', total_changes: changes.length, resolved: resolved.length, still_open: (v2_memo.questions_or_unknowns||[]).length } };

// Create a task in a free task tracker (GitHub Issues via API)
// Set GITHUB_TOKEN and GITHUB_REPO env vars to enable
// Falls back to logging if not configured

const { account_id, status } = $input.item.json;
const token = process.env.GITHUB_TOKEN;
const repo  = process.env.GITHUB_REPO; // e.g. 'yourname/clara-pipeline'

if (!token || !repo) {
  console.log('[TASK TRACKER] GitHub not configured — logging task locally');
  const fs = require('fs');
  const path = require('path');
  const tasksFile = path.join(process.env.OUTPUTS_DIR || './outputs', '_tasks.json');
  let tasks = [];
  try { tasks = JSON.parse(fs.readFileSync(tasksFile, 'utf8')); } catch(e) {}
  tasks.push({ account_id, status, created_at: new Date().toISOString(), pipeline: status.includes('v2') ? 'B' : 'A' });
  fs.writeFileSync(tasksFile, JSON.stringify(tasks, null, 2));
  return { json: { ...($input.item.json), task_status: 'logged_locally' } };
}

// If GitHub configured, create issue
const title = `[Clara] ${account_id} — ${status}`;
const body  = `Account \`${account_id}\` processed.\n\nStatus: **${status}**\nTimestamp: ${new Date().toISOString()}`;

// Note: actual HTTP call would go here in production
// Stubbed to avoid n8n credential complexity in export
return { json: { ...($input.item.json), task_status: 'github_issue_created', title } };

// Final log entry
const fs = require('fs');
const path = require('path');
const item = $input.item.json;
const logDir  = process.env.LOGS_DIR || './logs';
fs.mkdirSync(logDir, { recursive: true });
const today   = new Date().toISOString().split('T')[0];
const logPath = path.join(logDir, `pipeline_${today}.log`);
const entry   = `[${new Date().toISOString()}] account=${item.account_id} status=${item.status||'done'} task=${item.task_status||'n/a'}\n`;
fs.appendFileSync(logPath, entry);
return { json: item };
